# Безопасный ввод
def safe_int(prompt, mn=None, mx=None):
    while True:
        try:
            v = int(input(prompt))
            if mn is not None and v < mn: raise ValueError(f'>= {mn}')
            if mx is not None and v > mx: raise ValueError(f'<= {mx}')
            return v
        except ValueError as e:
            print(f'Ошибка: {e}')

age = safe_int('Возраст (1-120): ', 1, 120)
print(f'Возраст: {age}')

def bubble_sort(arr):
    n = len(arr); swaps = 0
    for i in range(n):
        swapped = False
        for j in range(n-i-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
                swaps += 1; swapped = True
        if not swapped: break
    return arr, swaps

def selection_sort(arr):
    n = len(arr); swaps = 0
    for i in range(n):
        mi = i
        for j in range(i+1,n):
            if arr[j] < arr[mi]: mi = j
        if mi != i:
            arr[i],arr[mi]=arr[mi],arr[i]; swaps+=1
    return arr, swaps

data = [64,34,25,12,22,11,90]
b,bs = bubble_sort(data.copy())
s,ss = selection_sort(data.copy())
print(f'Пузырьковая: {b}, обменов: {bs}')
print(f'Выбором:     {s}, обменов: {ss}')

import functools

@functools.lru_cache(maxsize=None)
def fib(n):
    if n<=1: return n
    return fib(n-1)+fib(n-2)

print([fib(i) for i in range(10)])

def power(base, exp):
    if exp==0: return 1
    if exp%2==0:
        half = power(base, exp//2)
        return half*half
    return base * power(base,exp-1)

print(power(2,10))  # 1024

def hanoi(n, src, dst, aux):
    if n==1:
        print(f'Диск 1: {src} -> {dst}')
        return
    hanoi(n-1, src, aux, dst)
    print(f'Диск {n}: {src} -> {dst}')
    hanoi(n-1, aux, dst, src)

