class Person:
    def __init__(self, name, age):
        self.name=name; self.age=age
    def introduce(self):
        return f'Меня зовут {self.name}, мне {self.age} лет'

class Student(Person):
    def __init__(self, name, age, group):
        super().__init__(name, age)
        self.group=group; self.grades=[]
    def introduce(self):
        return f'{super().introduce()}, группа {self.group}'

class Teacher(Person):
    def __init__(self, name, age, subject):
        super().__init__(name, age)
        self.subject=subject
    def introduce(self):
        return f'{super().introduce()}, преподаю {self.subject}'

people = [Student('Анна',20,'ИТ-21'), Teacher('Иван Ив.',45,'Инф.')]
for p in people:
    print(p.introduce())
